-- ============================================================================
-- 046_arith_average.sql
-- Question-bank seed: Arithmetic chapter "Average" -- 40 single-answer MCQs
-- from ACTUAL previous-year papers (SBI/IBPS/RBI/Canara PO & Clerk, SSC CGL/CHSL,
-- TS/AP ICET, TCS NQT/Infosys/Wipro/Cognizant) via IndiaBix, PrepInsta, Testbook,
-- Adda247, Oliveboard, CareerPower, Examveda, 2IIM, GeeksforGeeks, Sawaal.
-- Series averages, weighted/combined, replacement, average speed, run-rate.
-- Exam-grade difficulty floor; answers independently recomputed; 4 distinct-valued
-- options, one correct; each carries a worked explanation. Depends on 023. Reuses the
-- idempotent _seed_arith_q helper (dollar-quoted). Safe to re-run.
-- ============================================================================

create or replace function public._seed_arith_q(p_chapter text, p_difficulty text, p_stem text, p_opts text[], p_correct int, p_explanation text) returns void language plpgsql as $$
declare v_subj uuid; v_chap uuid; v_qid uuid; i int;
begin
  select id into v_subj from public.subject where lower(name)='arithmetic' limit 1;
  if v_subj is null then raise exception 'Arithmetic subject not found (run 023 first)'; end if;
  select id into v_chap from public.chapter where subject_id=v_subj and lower(name)=lower(p_chapter) limit 1;
  if v_chap is null then raise exception 'Chapter % not found', p_chapter; end if;
  if exists (select 1 from public.question where chapter_id=v_chap and stem=p_stem) then return; end if;
  insert into public.question (subject_id, chapter_id, kind, difficulty, answer_type, stem, explanation)
  values (v_subj, v_chap, 'standard', p_difficulty, 'single', p_stem, p_explanation) returning id into v_qid;
  for i in 1..array_length(p_opts,1) loop
    insert into public.question_option (question_id, label, is_correct, position) values (v_qid, p_opts[i], i=p_correct, i-1);
  end loop;
end; $$;

-- Average (40 questions)
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the first 20 natural numbers.$q$,array[$q$10$q$,$q$10.5$q$,$q$11$q$,$q$20.5$q$],2,$q$Average of first n natural numbers = (n+1)/2 = (20+1)/2 = 10.5.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of all even numbers from 2 to 40 inclusive.$q$,array[$q$20$q$,$q$21$q$,$q$22$q$,$q$19$q$],2,$q$Even numbers 2,4,...,40 form an AP; average = (first+last)/2 = (2+40)/2 = 21.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of 25, 30, 35, 40 and 45.$q$,array[$q$33$q$,$q$34$q$,$q$35$q$,$q$36$q$],3,$q$Sum = 25+30+35+40+45 = 175; average = 175/5 = 35.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the first 10 odd numbers.$q$,array[$q$9$q$,$q$10$q$,$q$11$q$,$q$12$q$],2,$q$First 10 odd numbers 1,3,...,19; average of first n odd numbers = n = 10 (or (1+19)/2=10).$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the first five positive multiples of 7.$q$,array[$q$19$q$,$q$20$q$,$q$21$q$,$q$22$q$],3,$q$Multiples 7,14,21,28,35; sum=105; average=105/5=21 (middle term of the AP).$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the first 15 multiples of 8.$q$,array[$q$60$q$,$q$62$q$,$q$64$q$,$q$72$q$],3,$q$Average of first n multiples of k = k(n+1)/2 = 8*(15+1)/2 = 8*8 = 64.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the squares of the first five natural numbers.$q$,array[$q$10$q$,$q$11$q$,$q$12$q$,$q$13$q$],2,$q$Squares 1,4,9,16,25; sum=55; average=55/5=11.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the first 40 natural numbers.$q$,array[$q$20$q$,$q$20.5$q$,$q$21$q$,$q$19.5$q$],2,$q$Average = (n+1)/2 = (40+1)/2 = 20.5.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of all prime numbers between 30 and 50.$q$,array[$q$38.6$q$,$q$39.8$q$,$q$40.2$q$,$q$41.0$q$],2,$q$Primes 31,37,41,43,47; sum=199; average=199/5=39.8.$q$);
select public._seed_arith_q($q$Average$q$,'easy',$q$Find the average of the first 10 even numbers.$q$,array[$q$10$q$,$q$11$q$,$q$12$q$,$q$9$q$],2,$q$Even numbers 2,4,...,20; average=(2+20)/2=11.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average of 11 numbers is 30. The average of the first 6 numbers is 28 and that of the last 6 is 32. Find the 6th number.$q$,array[$q$28$q$,$q$30$q$,$q$32$q$,$q$34$q$],2,$q$Total=11*30=330. First 6=6*28=168, last 6=6*32=192. The 6th is counted in both, so 6th = 168+192-330 = 30.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$A class has 30 students with average marks 12 and another class has 20 students with average marks 17. Find the combined average marks of all 50 students.$q$,array[$q$13.5$q$,$q$14$q$,$q$14.5$q$,$q$15$q$],2,$q$Combined = (30*12 + 20*17)/50 = (360+340)/50 = 700/50 = 14.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average of 6 numbers is 8. If the average of 4 of them is 5, find the average of the remaining 2 numbers.$q$,array[$q$12$q$,$q$13$q$,$q$14$q$,$q$15$q$],3,$q$Total=6*8=48; the 4 numbers=4*5=20; remaining 2 sum=28; average=28/2=14.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average age of 40 students is 15 years. When the teacher's age is included, the average becomes 15.5 years. Find the teacher's age.$q$,array[$q$30.5$q$,$q$33.5$q$,$q$35.5$q$,$q$40.5$q$],3,$q$New total (41 people)=41*15.5=635.5; old total=40*15=600; teacher=635.5-600=35.5 years.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average salary of 20 workers is Rs.4000. Including 5 managers, the average of all 25 becomes Rs.4600. Find the average salary of a manager.$q$,array[$q$Rs.6800$q$,$q$Rs.7000$q$,$q$Rs.7200$q$,$q$Rs.7500$q$],2,$q$Managers' total = 25*4600 - 20*4000 = 115000 - 80000 = 35000; average = 35000/5 = Rs.7000.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average weight of A, B and C is 45 kg. The average of A and B is 40 kg and that of B and C is 43 kg. Find B's weight.$q$,array[$q$29$q$,$q$30$q$,$q$31$q$,$q$33$q$],3,$q$A+B+C=135; A+B=80; B+C=86. Adding the last two: A+2B+C=166; subtract total: B=166-135=31 kg.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average of 50 numbers is 38. If two numbers, 45 and 55, are discarded, find the average of the remaining numbers.$q$,array[$q$36.5$q$,$q$37$q$,$q$37.5$q$,$q$38.5$q$],3,$q$Total=50*38=1900; remove 45+55=100 → 1800 over 48 numbers; average=1800/48=37.5.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$40 boys have an average height of 62 cm and 60 girls have an average height of 52 cm. Find the average height of all 100 students.$q$,array[$q$54$q$,$q$55$q$,$q$56$q$,$q$57$q$],3,$q$Combined = (40*62 + 60*52)/100 = (2480+3120)/100 = 5600/100 = 56 cm.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average of 9 results is 50. The average of the first 5 is 54 and of the last 5 is 47. Find the 5th result.$q$,array[$q$50$q$,$q$52$q$,$q$54$q$,$q$55$q$],4,$q$First 5=270, last 5=235; the 5th is in both, so 5th = 270+235 - 9*50 = 505-450 = 55.$q$);
select public._seed_arith_q($q$Average$q$,'medium',$q$The average marks of 50 students is 65. If 10 students with an average of 40 leave, find the new average of the remaining 40 students.$q$,array[$q$70$q$,$q$70.5$q$,$q$71.25$q$,$q$72$q$],3,$q$Total=50*65=3250; leavers=10*40=400; remaining=2850 over 40; average=2850/40=71.25.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$The average weight of 8 persons increases by 2.5 kg when a new person replaces one weighing 65 kg. Find the weight of the new person.$q$,array[$q$80$q$,$q$82.5$q$,$q$85$q$,$q$87.5$q$],3,$q$Total increase = 8*2.5 = 20 kg. New person = 65 + 20 = 85 kg.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$The average age of a class of 20 students falls by 3 months when a student aged 18 years is replaced by a new student. Find the new student's age.$q$,array[$q$12$q$,$q$13$q$,$q$14$q$,$q$15$q$],2,$q$Total decrease = 20 * 3 months = 60 months = 5 years. New age = 18 - 5 = 13 years.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$A man travels from A to B at 40 km/h and returns at 60 km/h. Find his average speed for the whole journey.$q$,array[$q$48$q$,$q$50$q$,$q$52$q$,$q$45$q$],1,$q$To-and-fro (equal distance) → average = 2xy/(x+y) = 2*40*60/(100) = 4800/100 = 48 km/h.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$A boat covers 30 km upstream at 10 km/h and 30 km downstream at 15 km/h. Find the average speed for the entire trip.$q$,array[$q$12$q$,$q$12.5$q$,$q$13$q$,$q$11.5$q$],1,$q$Total distance=60 km; time = 30/10 + 30/15 = 3+2 = 5 h; average = 60/5 = 12 km/h.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$A person covers the first half of a distance at 30 km/h and the second half at 60 km/h. Find the average speed for the whole distance.$q$,array[$q$40$q$,$q$42$q$,$q$45$q$,$q$50$q$],1,$q$Equal halves → harmonic mean = 2*30*60/(30+60) = 3600/90 = 40 km/h.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$The average monthly income of a family of 4 is Rs.15000. When a member earning Rs.12000 is replaced by another, the average rises to Rs.15750. Find the new member's income.$q$,array[$q$Rs.14000$q$,$q$Rs.15000$q$,$q$Rs.16000$q$,$q$Rs.18000$q$],2,$q$Total rise = 4*750 = 3000. New member = 12000 + 3000 = Rs.15000.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$A car covers three equal stretches of a road at speeds of 20 km/h, 30 km/h and 60 km/h respectively. Find its average speed.$q$,array[$q$30$q$,$q$33.33$q$,$q$36$q$,$q$40$q$],1,$q$Equal parts → average = 3/(1/20+1/30+1/60) = 3/(3/60+2/60+1/60) = 3/(6/60) = 3/0.1 = 30 km/h.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$A man goes to office by walking at 4 km/h and returns by cycle at 12 km/h along the same route. Find his average speed.$q$,array[$q$6$q$,$q$7$q$,$q$8$q$,$q$5$q$],1,$q$Equal distance → 2*4*12/(4+12) = 96/16 = 6 km/h.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$The average age of a husband and wife was 23 years when they married 5 years ago. Now, with a child, the average age of the 3-member family is 20 years. Find the age of the child.$q$,array[$q$3$q$,$q$4$q$,$q$5$q$,$q$6$q$],2,$q$Now husband+wife = 2*23 + 2*5 = 46+10 = 56; family total = 3*20 = 60; child = 60-56 = 4 years.$q$);
select public._seed_arith_q($q$Average$q$,'hard',$q$The average weight of 6 persons increases by 3.5 kg when two persons weighing 55 kg and 63 kg are replaced by two new persons. Find the total weight of the two new persons.$q$,array[$q$135$q$,$q$137$q$,$q$139$q$,$q$141$q$],3,$q$Total increase = 6*3.5 = 21 kg. New two = (55+63) + 21 = 118+21 = 139 kg.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$In a cricket team of 11 players, the captain is 26 years old and the wicketkeeper is 3 years older than the captain. If the average age of the remaining 9 players is 1 year less than the average age of the whole team, find the average age of the team.$q$,array[$q$22$q$,$q$23$q$,$q$24$q$,$q$25$q$],2,$q$Let team avg = x. Captain+WK = 26+29 = 55. Remaining 9 avg = x-1, so 11x - 55 = 9(x-1) → 11x-55 = 9x-9 → 2x = 46 → x = 23 years.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$The average of 10 numbers is 15. Later it is found that one number was read as 26 instead of 62. Find the correct average.$q$,array[$q$17.4$q$,$q$18.6$q$,$q$19.2$q$,$q$16.8$q$],2,$q$Error = 62-26 = 36 added back. Correct total = 150+36 = 186; correct average = 186/10 = 18.6.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$In a 50-over match a team needs 282 runs to win. If the run rate in the first 10 overs was 4.8, what run rate is required in the remaining 40 overs to win?$q$,array[$q$5.65$q$,$q$5.75$q$,$q$5.85$q$,$q$5.95$q$],3,$q$Runs in 10 overs = 10*4.8 = 48; remaining = 282-48 = 234 over 40 overs; required RR = 234/40 = 5.85.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$The average of 25 results is 18. The average of the first 12 is 14 and that of the last 12 is 17. Find the 13th result.$q$,array[$q$76$q$,$q$78$q$,$q$80$q$,$q$82$q$],2,$q$Total=25*18=450; first 12=168, last 12=204; the 13th is left out, so 13th = 450 - 168 - 204 = 78.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$The average marks of 30 students is 55. Later it is found that two marks were entered as 45 and 68 instead of the correct 54 and 86. Find the correct average.$q$,array[$q$55.9$q$,$q$56.4$q$,$q$55.5$q$,$q$56.9$q$],1,$q$Correction = (54+86) - (45+68) = 140-113 = 27; correct total = 1650+27 = 1677; average = 1677/30 = 55.9.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$A batsman's average increases by 3 runs after he scores 84 in his 17th innings. Find his new average after the 17th innings.$q$,array[$q$33$q$,$q$34$q$,$q$35$q$,$q$36$q$],4,$q$Let avg after 16 innings = a. (16a+84)/17 = a+3 → 16a+84 = 17a+51 → a = 33; new average = 33+3 = 36.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$A bowler's bowling average is 12.4 runs per wicket. In a match he takes 5 wickets for 26 runs, and his average drops by 0.4. Find the number of wickets he had taken before this match.$q$,array[$q$64$q$,$q$72$q$,$q$80$q$,$q$85$q$],4,$q$Let w = wickets before. (12.4w + 26)/(w+5) = 12.0 → 12.4w+26 = 12w+60 → 0.4w = 34 → w = 85.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$In a 50-over match a team needs to chase 250 runs. If the run rate in the first 10 overs was 6, find the required run rate for the remaining 40 overs.$q$,array[$q$4.25$q$,$q$4.5$q$,$q$4.75$q$,$q$5$q$],3,$q$Runs in 10 overs = 60; remaining = 250-60 = 190 over 40 overs; required RR = 190/40 = 4.75.$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$The average age of 30 students in a class is 14 years. When the class teacher's age is added, the average increases by exactly 1 year. Find the teacher's age.$q$,array[$q$44$q$,$q$45$q$,$q$46$q$,$q$48$q$],2,$q$New average (31 people) = 15; teacher = 31*15 - 30*14 = 465 - 420 = 45 years. (Shortcut: 14 + 31*1 = 45.)$q$);
select public._seed_arith_q($q$Average$q$,'very_hard',$q$A cricketer has a certain average for 10 innings. In the 11th innings he scores 108, raising his average by 6. Find his new average after 11 innings.$q$,array[$q$42$q$,$q$46$q$,$q$48$q$,$q$50$q$],3,$q$Let old avg = a. (10a+108)/11 = a+6 → 10a+108 = 11a+66 → a = 42; new average = 42+6 = 48.$q$);

drop function public._seed_arith_q(text,text,text,text[],int,text);
